var KITA_TITLES = {
  avrupa:'🇪🇺 Avrupa Kıtası',
  amerika:'🌎 Amerika Kıtası',
  asya:'🌏 Asya Kıtası',
  afrika:'🌍 Afrika Kıtası',
  okyanusya:'🦘 Okyanusya'
};
var ORDER = ['avrupa','amerika','asya','afrika','okyanusya'];
function card(d){
  var h='<div class="dsg-card"><div class="dsg-card-hd">';
  h+='<div class="dsg-flag">'+(d.bayrak||'🏳️')+'</div>';
  h+='<div class="dsg-card-name">'+d.name+'</div>';
  h+='<div class="dsg-card-country">'+(d.ulke||'')+'</div>';
  h+='</div><div class="dsg-card-body">';
  if(d.sehir||d.eyalet) h+='<div class="dsg-row">📍 '+(d.sehir?d.sehir+', ':'')+''+(d.eyalet||'')+'</div>';
  if(d.tel) h+='<div class="dsg-row">📞 <a href="tel:'+d.tel.replace(/\s/g,'')+'">'+d.tel+'</a></div>';
  if(d.web&&d.web.startsWith('http')) h+='<div class="dsg-row">🌐 <a href="'+d.web+'" target="_blank" rel="noopener">'+d.web.replace('https://','').replace('http://','').substring(0,35)+'</a></div>';
  h+='</div></div>';
  return h;
}
function render(items){
  var out=document.getElementById('dsg-out');
  document.getElementById('dsg-count').textContent=items.length;
  if(!items.length){out.innerHTML='<div class="dsg-empty">Sonuç bulunamadı.</div>';return;}
  var groups={};
  items.forEach(function(d){
    var k=d.kita||'avrupa';
    if(!groups[k])groups[k]=[];groups[k].push(d);
  });
  var h='';
  ORDER.forEach(function(kita){
    if(!groups[kita])return;
    h+='<div class="dsg-sec-title">'+(KITA_TITLES[kita]||kita)+' ('+groups[kita].length+')</div>';
    h+='<div class="dsg-grid">';
    groups[kita].forEach(function(d){h+=card(d);});
    h+='</div>';
  });
  out.innerHTML=h;
}
var DSG={
  filter:function(kita,btn){
    document.querySelectorAll('.dsg-fb').forEach(function(b){b.classList.remove('on');});
    btn.classList.add('on');
    document.getElementById('dsg-inp').value='';
    render(kita==='all'?DATA:DATA.filter(function(d){return (d.kita||'avrupa')===kita;}));
  },
  search:function(val){
    var q=val.toLowerCase().trim();
    render(q?DATA.filter(function(d){return (d.name+(d.ulke||'')+(d.sehir||'')).toLowerCase().includes(q);}):DATA);
  }
};
render(DATA);
</script>
